const addExampleButtons = () => {
  document.querySelectorAll('.card').forEach((card, idx)=>{
    const titleEl = card.querySelector('.sample-title');
    let key = 'unknown';
    if(titleEl){
      const di = titleEl.getAttribute('data-i18n') || '';
      const m = di.match(/^sample\.([^.]+)\.([^.]+)\.title$/);
      if(m) key = `${m[1]}.${m[2]}`;
    }
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'btn example-btn';
    btn.textContent = translations[document.documentElement.lang]?.['action.showExample'] || 'Show example';
    btn.setAttribute('data-example-key', key);
    btn.style.marginTop = '.5rem';
    card.appendChild(btn);
  });

  document.body.addEventListener('click', (e)=>{
    const btn = e.target.closest('.example-btn');
    if(!btn) return;
    const k = btn.getAttribute('data-example-key');
    openExampleModal(k);
  });
};

const modal = document.getElementById('example-modal');
const modalTitle = document.getElementById('example-modal-title');
const modalBody = document.getElementById('example-modal-body');
const modalClose = document.getElementById('example-modal-close');
const navLangEl = document.querySelector('.nav-lang');

const openExampleModal = (key) => {
  const lang = document.documentElement.lang || 'en';
  const item = examples[key] || examples['business.contentWriting'];
  const data = item[lang] || item.en;
  modalTitle.textContent = data.title || '';
  modalBody.innerHTML = data.body || '';
  modal.classList.add('open');
  modal.setAttribute('aria-hidden', 'false');
  if(navLangEl) navLangEl.style.display = 'none';
  modalClose.focus();
};

const closeExampleModal = ()=>{
  modal.classList.remove('open');
  modal.setAttribute('aria-hidden', 'true');
  if(navLangEl) navLangEl.style.display = '';
};

modalClose?.addEventListener('click', closeExampleModal);
modal?.addEventListener('click', (e)=>{ if(e.target === modal) closeExampleModal(); });

const addActionTranslationKey = ()=>{
  Object.keys(translations).forEach(lang=>{
    translations[lang]['action.showExample'] = translations[lang]['action.showExample'] || (lang==='ar' ? 'عرض المثال' : (lang==='fr' ? 'Voir l\'exemple' : (lang==='es' ? 'Mostrar ejemplo' : 'Show example')));
  });
};
addActionTranslationKey();

const observeLangChange = ()=>{
  const el = document.documentElement;
  const observer = new MutationObserver(()=>{
    const lang = el.lang || 'en';
    document.querySelectorAll('.example-btn').forEach(b=> b.textContent = translations[lang]['action.showExample'] || 'Show example');
  });
  observer.observe(el, {attributes:true, attributeFilter:['lang']});
};

addExampleButtons();
observeLangChange();

document.addEventListener('keydown', (e)=>{ if(e.key==='Escape' && modal.classList.contains('open')) closeExampleModal(); });
const themeToggle = document.getElementById('theme-toggle');
const currentTheme = localStorage.getItem('theme') || 'light';

if (currentTheme === 'dark') {
    document.documentElement.setAttribute('data-theme', 'dark');
    themeToggle.textContent = '🌙';
}

themeToggle.addEventListener('click', () => {
    let theme = document.documentElement.getAttribute('data-theme');
    if (theme === 'dark') {
        document.documentElement.setAttribute('data-theme', 'light');
        localStorage.setItem('theme', 'light');
        themeToggle.textContent = '☀️';
    } else {
        document.documentElement.setAttribute('data-theme', 'dark');
        localStorage.setItem('theme', 'dark');
        themeToggle.textContent = '🌙';
    }
});